{"content": "import shutil, os, subprocess, json

TOKEN = subprocess.run(
    "grep -A3 'oauth_token' ~/.config/gh/hosts.yml | head -1 | awk '{print $2}'",
    shell=True, capture_output=True, text=True
).stdout.strip()

BASE = '/root/sites'
BUILDER_SITES = '/root/paragu-ai-builder/sites'
TEMPLATE_SRC = '/root/nudo/repo'

def create_repo(name, commit_msg="Initial commit — scaffold from paragu-ai-builder"):
    """Scaffold a repo for a client site"""
    dest = f'{BASE}/{name}'

    # Clean if exists
    if os.path.exists(dest):
        shutil.rmtree(dest)
    os.makedirs(dest)

    # 1. Create minimal project files
    # package.json
    pkg = {
        "name": name,
        "version": "0.1.0",
        "private": True,
        "scripts": {"dev": "next dev", "build": "next build", "start": "next start", "lint": "eslint"},
        "dependencies": {
            "lucide-react": "^1.14.0",
            "next": "16.2.4",
            "react": "19.2.4",
            "react-dom": "19.2.4"
        },
        "devDependencies": {
            "@tailwindcss/postcss": "^4",
            "@types/node": "^20",
            "@types/react": "^19",
            "@types/react-dom": "^19",
            "eslint": "^9",
            "eslint-config-next": "16.2.4",
            "tailwindcss": "^4",
            "typescript": "^5"
        }
    }
    with open(f'{dest}/package.json', 'w') as f:
        json.dump(pkg, f, indent=2)

    # next.config.ts
    next_config = """import type { NextConfig } from "next"

const securityHeaders = [
  { key: 'X-DNS-Prefetch-Control', value: 'on' },
  { key: 'Strict-Transport-Security', value: 'max-age=63072000; includeSubDomains; preload' },
  { key: 'X-Frame-Options', value: 'DENY' },
  { key: 'X-Content-Type-Options', value: 'nosniff' },
  { key: 'Referrer-Policy', value: 'strict-origin-when-cross-origin' },
  { key: 'Permissions-Policy', value: 'camera=(), microphone=(), geolocation=()' },
]

const config: NextConfig = {
  output: "standalone",
  poweredByHeader: false,
  async headers() {
    return [
      { source: '/(.*)', headers: securityHeaders },
      { source: '/images/(.*)', headers: [{ key: 'Cache-Control', value: 'public, max-age=31536000, immutable' }] },
    ]
  },
}
export default config
"""
    with open(f'{dest}/next.config.ts', 'w') as f:
        f.write(next_config)

    # tsconfig.json
    tsconfig = """{
  "compilerOptions": {
    "target": "ES2017",
    "lib": ["dom", "dom.iterable", "esnext"],
    "allowJs": true,
    "skipLibCheck": true,
    "strict": true,
    "noEmit": true,
    "esModuleInterop": true,
    "module": "esnext",
    "moduleResolution": "bundler",
    "resolveJsonModule": true,
    "isolatedModules": true,
    "jsx": "react-jsx",
    "incremental": true,
    "plugins": [{ "name": "next" }],
    "paths": { "@/*": ["./*"] }
  },
  "include": ["next-env.d.ts", "**/*.ts", "**/*.tsx", ".next/types/**/*.ts", ".next/dev/types/**/*.ts", "**/*.mts"],
  "exclude": ["node_modules"]
}
"""
    with open(f'{dest}/tsconfig.json', 'w') as f:
        f.write(tsconfig)

    # postcss.config.mjs
    with open(f'{dest}/postcss.config.mjs', 'w') as f:
        f.write("""const config = { plugins: { "@tailwindcss/postcss": {} } }
export default config
""")

    # .gitignore
    with open(f'{dest}/.gitignore', 'w') as f:
        f.write("node_modules\n.next\n*.local\n.env\n.env.local\n.env.*.local\n")

    # .npmrc
    with open(f'{dest}/.npmrc', 'w') as f:
        f.write("auto-install-peers=true\nstrict-peer-dependencies=false\n")

    # Dockerfile
    dockerfile = f"""FROM node:20-alpine AS deps
WORKDIR /app
RUN apk add --no-cache libc6-compat
COPY package.json package-lock.json* ./
RUN npm install

FROM node:20-alpine AS builder
WORKDIR /app
COPY --from=deps /app/node_modules ./node_modules
COPY . .
ENV NODE_ENV=production NEXT_TELEMETRY_DISABLED=1
RUN npm run build

FROM node:20-alpine AS runner
WORKDIR /app
ENV NODE_ENV=production NEXT_TELEMETRY_DISABLED=1 PORT=3000 HOSTNAME="0.0.0.0"
RUN addgroup --system --gid 1001 nodejs && adduser --system --uid 1001 nextjs
COPY --from=builder --chown=nextjs:nodejs /app/.next/standalone ./
COPY --from=builder --chown=nextjs:nodejs /app/.next/static ./.next/static
COPY --from=builder --chown=nextjs:nodejs /app/public ./public
USER nextjs
EXPOSE 3000
HEALTHCHECK --interval=30s --timeout=10s --start-period=10s --retries=3 CMD wget --no-verbose --tries=1 --spider http://127.0.0.1:3000/ || exit 1
CMD ["node", "server.js"]
"""
    with open(f'{dest}/Dockerfile', 'w') as f:
        f.write(dockerfile)

    # docker-compose.yml
    compose = f"""services:
  web:
    build: .
    image: {name}:prod
    ports:
      - "3000:3000"
    environment:
      - NODE_ENV=production
    restart: unless-stopped
    labels:
      - "traefik.enable=true"
      - "traefik.http.routers.{name}.rule=Host(`{name}.paragu-ai.com`)"
      - "traefik.http.routers.{name}.entrypoints=websecure"
      - "traefik.http.services.{name}.loadbalancer.server.port=3000"
"""
    with open(f'{dest}/docker-compose.yml', 'w') as f:
        f.write(compose)

    # 2. Copy client data from builder
    src = f'{BUILDER_SITES}/{name}'
    if os.path.isdir(src):
        # Copy content
        if os.path.isdir(f'{src}/content'):
            shutil.copytree(f'{src}/content', f'{dest}/content')
        # Copy pages
        if os.path.isdir(f'{src}/pages'):
            shutil.copytree(f'{src}/pages', f'{dest}/pages')
        # Copy images
        if os.path.isdir(f'{src}/images'):
            shutil.copytree(f'{src}/images', f'{dest}/public/images')
        # Copy blog
        if os.path.isdir(f'{src}/blog'):
            shutil.copytree(f'{src}/blog', f'{dest}/blog')
        # Copy assets
        if os.path.isdir(f'{src}/assets'):
            shutil.copytree(f'{src}/assets', f'{dest}/public/assets')
        # Copy docs
        if os.path.isdir(f'{src}/docs'):
            shutil.copytree(f'{src}/docs', f'{dest}/docs')
        # Copy individual files
        for fname in ['site.json', 'tokens.json', 'images.json', 'testimonials.json', 
                       'email-nurture.json', '.env.example']:
            fp = f'{src}/{fname}'
            if os.path.isfile(fp):
                shutil.copy2(fp, f'{dest}/{fname}')

        # Copy marketing
        if os.path.isdir(f'{src}/marketing'):
            shutil.copytree(f'{src}/marketing', f'{dest}/marketing')
        # Copy dist (email templates, social assets)
        if os.path.isdir(f'{src}/dist'):
            shutil.copytree(f'{src}/dist', f'{dest}/dist')

    # 3. Create minimal Next.js app structure
    os.makedirs(f'{dest}/src/app', exist_ok=True)
    os.makedirs(f'{dest}/src/lib', exist_ok=True)
    os.makedirs(f'{dest}/src/components', exist_ok=True)

    # Read site.json for page rendering
    site_data = {}
    site_path = f'{dest}/site.json'
    if os.path.isfile(site_path):
        with open(site_path) as f:
            site_data = json.load(f)

    site_name = site_data.get('siteName', name)
    site_description = site_data.get('description', site_data.get('tagline', 'Website'))
    lang = site_data.get('locale', site_data.get('defaultLocale', 'es'))
    token_path = f'{dest}/tokens.json'

    # Generate globals.css from tokens
    colors = {'primary': '#1a1a2e', 'secondary': '#16213e', 'accent': '#e94560', 
              'background': '#ffffff', 'foreground': '#1a1a2e'}
    fonts = {'heading': 'Inter, system-ui, sans-serif', 'body': 'Inter, system-ui, sans-serif'}

    if os.path.isfile(token_path):
        with open(token_path) as f:
            tokens = json.load(f)
        if 'colors' in tokens:
            colors.update(tokens['colors'])
        if 'font' in tokens:
            if isinstance(tokens['font'], dict):
                fonts.update(tokens['font'])

    css = f"""@import "tailwindcss";

@theme {{
  --color-primary: {colors.get('primary', '#1a1a2e')};
  --color-secondary: {colors.get('secondary', '#16213e')};
  --color-accent: {colors.get('accent', '#e94560')};
  --color-background: {colors.get('background', '#ffffff')};
  --color-foreground: {colors.get('foreground', '#1a1a2e')};
  --color-muted: {colors.get('muted', '#6b7280')};
  --color-surface: {colors.get('surface', '#f8f9fa')};
  --font-body: {fonts.get('body', 'Inter, system-ui, sans-serif')};
  --font-heading: {fonts.get('heading', 'Inter, system-ui, sans-serif')};
}}

@layer base {{
  body {{
    background-color: {colors.get('background', '#ffffff')};
    color: {colors.get('foreground', '#1a1a2e')};
    font-family: {fonts.get('body', 'Inter, system-ui, sans-serif')};
  }}
}}
"""
    with open(f'{dest}/src/app/globals.css', 'w') as f:
        f.write(css)

    # Layout
    layout = f"""import type {{ Metadata }} from 'next'
import './globals.css'

export const metadata: Metadata = {{
  title: '{site_name}',
  description: '{site_description}',
}}

export default function RootLayout({{ children }}: {{ children: React.ReactNode }}) {{
  return (
    <html lang="{lang}" className="scroll-smooth">
      <body>{{children}}</body>
    </html>
  )
}}
"""
    with open(f'{dest}/src/app/layout.tsx', 'w') as f:
        f.write(layout)

    # Simple page renderer that reads content and renders sections
    page = """import { readFileSync, existsSync } from 'fs'
import path from 'path'

interface PageConfig {
  id: string
  title: string
  sections: string[]
  [key: string]: any
}

interface ContentData {
  [key: string]: any
}

function getContent(): ContentData {
  const contentPath = path.join(process.cwd(), 'content', 'es.json')
  if (existsSync(contentPath)) {
    return JSON.parse(readFileSync(contentPath, 'utf-8'))
  }
  return {}
}

function getPages() {
  const pagesDir = path.join(process.cwd(), 'pages')
  try {
    const pageFiles = require('fs').readdirSync(pagesDir)
    const pages: Record<string, PageConfig> = {}
    for (const file of pageFiles) {
      if (file.endsWith('.json')) {
        const data = JSON.parse(readFileSync(path.join(pagesDir, file), 'utf-8'))
        pages[file.replace('.json', '')] = data
      }
    }
    return pages
  } catch {
    return { home: { id: 'home', title: 'Home', sections: ['hero'] } }
  }
}

export default function HomePage() {
  const content = getContent()
  const pages = getPages()
  const homePage = pages['home'] || pages['index'] || { id: 'home', title: 'Home' }

  return (
    <main className="min-h-screen">
      <h1 className="text-4xl font-bold text-center py-12">
        {homePage.title || content?.title || 'Welcome'}
      </h1>

      {homePage.sections?.map((section: string) => {
        const sectionContent = content?.[section]
        if (!sectionContent) return null

        if (typeof sectionContent === 'string') {
          return <p key={section} className="text-lg px-4 py-2">{sectionContent}</p>
        }

        if (Array.isArray(sectionContent)) {
          return (
            <section key={section} className="px-4 py-8 max-w-6xl mx-auto">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {sectionContent.map((item: any, i: number) => (
                  <div key={i} className="p-6 rounded-lg" style={{backgroundColor: 'var(--color-surface, #f8f9fa)'}}>
                    {item.title && <h3 className="text-xl font-semibold mb-2">{item.title}</h3>}
                    {item.description && <p>{item.description}</p>}
                    {item.price && <p className="text-lg font-bold mt-2">{item.price}</p>}
                  </div>
                ))}
              </div>
            </section>
          )
        }

        return null
      })}
    </main>
  )
}
"""
    with open(f'{dest}/src/app/page.tsx', 'w') as f:
        f.write(page)

    # next-env.d.ts
    with open(f'{dest}/next-env.d.ts', 'w') as f:
        f.write('/// <reference types="next" />\n/// <reference types="next/image-types/global" />\n')

    # 4. Init git and push
    os.chdir(dest)
    subprocess.run(['git', 'init'], capture_output=True)
    subprocess.run(['git', 'add', '.'], capture_output=True)
    subprocess.run(['git', 'commit', '-m', commit_msg], capture_output=True)
    subprocess.run(['git', 'branch', '-M', 'main'], capture_output=True)
    subprocess.run([
        'git', 'remote', 'add', 'origin', 
        f'https://IvanWeissVanDerPol:{TOKEN}@github.com/Ai-Whisperers/{name}.git'
    ], capture_output=True)
    result = subprocess.run(['git', 'push', '-u', 'origin', 'main'], capture_output=True, text=True)

    return result.stdout[:200] + result.stderr[:200]

# Create all 8 repos
names = ['nexa-paraguay', 'nexa-propiedades', 'superspuma', 'stoicfinch',
         'granja-cabral', 'bufete-mendez', 'polki-squad', 'de-abasto-a-casa']

for n in names:
    print(f"\n=== Creating {n} ===")
    try:
        result = create_repo(n)
        print(result)
    except Exception as e:
        print(f"ERROR: {e}")
", "path": "/tmp/scaffold_repos.py"}
